(function () {const b=document.querySelectorAll(".adDemoButtons button"),c=document.getElementById("adPreviewFrame"),f=document.getElementById("activeAdTitle"),g=document.getElementById("activeAdCategory"),h=document.getElementById("activeAdLink");b.forEach(e=>{e.addEventListener("click",()=>{const t=e.dataset,a=t.title,$=t.category,d=t.url;b.forEach(e=>e.classList.remove("active")),e.classList.add("active"),f.textContent=a,g.textContent=$,h.href=d,c.title="".concat(a," mobile preview"),c.src=d})});})();